body.script:
//
    // JSON data of bare servers
    const bareServerData = {
        "servers": [
            "https://wisp.rhw.one/api/bare/",
            "https://phantomnetwork.cloud/bare/",
            "https://artclass.site/bare/",
            "https://shuttleproxy.com/bare/"
        ]
    };

    // Function to populate the dropdown menu
    function populateDropdown() {
        const select = document.getElementById('bareServerSelect');
        const servers = bareServerData.servers;

        servers.forEach((server) => {
            const option = document.createElement('option');
            option.value = server;
            option.textContent = server;
            select.appendChild(option);
        });
    }

    // Event listener to handle user selection and console messages
    document.getElementById('bareServerSelect').addEventListener('change', () => {
        const selectedServer = document.getElementById('bareServerSelect').value;
        console.log(`Selected server: ${selectedServer}`);
        // You can take further action with the selected server here
    });

    // Populate the dropdown on page load
    window.addEventListener('load', () => {
        populateDropdown();
        console.log('Dropdown menu populated.');
    });
//
